#property copyright "Copyright 2021, MetaQuotes Software Corp."
#property link      "https://www.mql5.com"
#property version   "1.00"
#property strict
#property indicator_chart_window
#property indicator_buffers 3
#property indicator_color1 Blue
#property indicator_color2 Red
#property indicator_color3 Green

extern int MA1 = 3;
extern int MA2 = 6;
extern int MA3 = 9;
extern double Max_MA_Range = 20.0; // in pips

double line1[];
double line2[];
double line3[];
double previousRangeHigh;
double previousRangeLow;

int OnInit()
{
   IndicatorBuffers(5);

   SetIndexBuffer(0,line1,INDICATOR_DATA);
   SetIndexBuffer(1,line2,INDICATOR_DATA);
   SetIndexBuffer(2,line3,INDICATOR_DATA);
   SetIndexStyle(0,DRAW_LINE);
   SetIndexStyle(1,DRAW_LINE);
   SetIndexStyle(2,DRAW_LINE);
   IndicatorShortName("LWMAs Breakout Indicator");

   return(INIT_SUCCEEDED);
}


int OnCalculate(const int rates_total,const int prev_calculated,const datetime &time[]
                ,const double &open[],const double &high[],const double &low[]
                ,const double &close[],const long &tick_volume[],const long &volume[]
                ,const int &spread[])
{
   int limit;
   limit = rates_total - prev_calculated;

   for (int i = limit; i >= 0; i--)
   {
      line1[i] = iLWMA(NULL,0,MA1,0,MODE_CLOSE,i);
      line2[i] = iLWMA(NULL,0,MA2,0,MODE_CLOSE,i);
      line3[i] = iLWMA(NULL,0,MA3,0,MODE_CLOSE,i);

      double sortedMA[3] = {line1[i], line2[i], line3[i]};
      ArraySort(sortedMA, WHOLE_ARRAY, 0, MODE_ASCEND);

      double difference = (sortedMA[2]-sortedMA[0]) / _Point;
      double maxRangeInPoints = Max_MA_Range * pow(10, -(_Digits - 2));

      if (difference <= maxRangeInPoints) {
         double rangeHigh = sortedMA[2];
         double rangeLow = sortedMA[0];
         previousRangeHigh = rangeHigh;
         previousRangeLow = rangeLow;
         DrawRangeBox(i, rangeLow, rangeHigh, "Range_Box");
      }

      if (i == 0) {
         CheckBreakout(previousRangeHigh, previousRangeLow, close[i]);
         DrawBreakoutLabel(rates_total - 1);
      }
   }

   return(rates_total);
}

void DrawRangeBox(int index, double rangeLow, double rangeHigh, string boxNamePrefix)
{
   ObjectCreate(0, boxNamePrefix + IntegerToString(index), OBJ_RECTANGLE_LABEL, 0, Time[index], rangeHigh, Time[index], rangeLow);
   ObjectSetInteger(0, boxNamePrefix + IntegerToString(index), OBJPROP_COLOR, clrLightGray);
   ObjectSetInteger(0, boxNamePrefix + IntegerToString(index), OBJPROP_BACK, true);
   ObjectSetInteger(0, boxNamePrefix + IntegerToString(index), OBJPROP_WIDTH, 2);
}

void DeleteOldRangeBoxes() {
   for(int i = ObjectsTotal(0) - 1; i >= 0; i--){
      string objName = ObjectName(0, i);
      if(StringFind(objName, "Range_Box") != -1){
         ObjectDelete(0, objName);
      }
   }
}

void CheckBreakout(double rangeHigh, double rangeLow, double currentClose)
{
   if (currentClose > rangeHigh || currentClose < rangeLow) {
      PlaySound("alert.wav");
      SendNotification("Breakout!");
   }
}

void DrawBreakoutLabel(int index)
{
   ObjectCreate(0, "breakout_label", OBJ_TEXT, 0, Time[index], High[index]);
   ObjectSetText("breakout_label", "BREAKOUT", 10, "Arial", clrYellow);
   ObjectSetInteger(0, "breakout_label", OBJPROP_CORNER, CORNER_RIGHT_UPPER);
   ObjectSetInteger(0, "breakout_label", OBJPROP_XDISTANCE, 20);
   ObjectSetInteger(0, "breakout_label", OBJPROP_YDISTANCE, 10);
}
